@query.field("user")
def resolve_user(obj, info, **kwargs):
    user_id = kwargs.get("id")
    current_user = info.context["current_user"]
    
    if current_user["id"] != int(user_id):
        return "Unauthorized"
    
    for user in users:
        if user["id"] == current_user["id"]:
            return user

